/// <summary>
/// The ETGSalesOrderWFTypeDocument workflow document class.
/// </summary>
[WorkflowDocIsQueueEnabledAttribute(true,"Sales order")]
class ETGSalesOrderWFTypeDocument 
extends WorkflowDocument implements SysErrorMessageHelpScopeIWorkflow
{
    SalesTable salesTable;


}

Method.Source:
public static ETGSalesOrderWFTypeDocument construct()
{
    return new ETGSalesOrderWFTypeDocument();
}

/// <summary>
///    Retrieves the name of the query to use for the document.
/// </summary>
/// <returns>
///    The name of the query to use for the document.
/// </returns>
QueryName getQueryName()
{
    return queryStr(ETGSalesOrderWFQuery);
}

private SalesTable getSalesTable(RecId  _recId)
{
    if (!salesTable)
    {
        salesTable = SalesTable::findRecId(_recId);
    }

    return salesTable;
}

/// <summary>
///    Calculates the total sales order order amount and converts it company currency.
/// </summary>
/// <param name="_companyId">
///    The company ID that corresponds to the workflow instance.
/// </param>
/// <param name="_tableId">
///    The table ID that corresponds to the workflow instance.
/// </param>
/// <param name="_recId">
///    The record ID that corresponds to the workflow instance.
/// </param>
/// <returns>
///     The total sales agreement order amount.
/// </returns>
public InvoiceAmountMST parmInvoiceAmount(CompanyId _companyId, TableId _tableId, RecId _recId)
{
    SalesLine        salesLine;
    InvoiceAmountMST amountMST;
    AgreementLineQuantityCommitment agreementLine;

    this.getSalesTable(_recId);

    if (salesTable)
    {
        select sum(LineAmount) from salesLine
            where salesLine.SalesId == salesTable.SalesId
            && salesLine.DataAreaId == salesTable.DataAreaId;

        amountMST = CurrencyExchangeHelper::amountCur2MST(salesLine.LineAmount, salesTable.CurrencyCode);
    }

    return amountMST;
}
